async fn process_layer(&self, dispatch_layer: DispatchLayer, cluster: Arc<Cluster>) {
    let mut try_again = true;
    let mut attempts = CONFIG.queue.host_candidate_attempts_per_layer;
    let mut current_layer_version = Some(dispatch_layer);

    while try_again && attempts > 0 {
        // Lines 280-298: Get host candidate from cache with validation closure
        let host_candidate = self
            .host_service
            .send(CheckOut {
                facility_id: layer.facility_id,
                show_id: layer.show_id,
                tags,
                cores: cores_requested,
                memory: layer.mem_min,
                validation: move |host| {
                    Self::validate_match(
                        host,
                        &layer_id,
                        &show_id,
                        cores_requested,
                        &allocation_service,
                        os.as_deref(),
                    )
                },
            })
            .await
            .expect("Host Cache actor is unresponsive");

        match host_candidate {
            Ok(CheckedOutHost(cluster_key, host)) => {
                // Lines 309-316: Send DispatchLayerMessage to dispatcher actor
                match self
                    .dispatcher_service
                    .send(DispatchLayerMessage {
                        layer,  // MOVED ownership here
                        host,
                    })
                    .await
                    .expect("Dispatcher actor is unresponsive")
                {
                    Ok(DispatchResult {
                        updated_host,
                        updated_layer,
                    }) => {
                        // Return updated host to cache
                        self.host_service
                            .send(CheckIn(cluster_key, CheckInPayload::Host(updated_host)))
                            .await
                            .expect("Host Cache actor is unresponsive");

                        if updated_layer.frames.is_empty() {
                            try_again = false;  // All frames consumed
                        } else {
                            current_layer_version = Some(updated_layer);
                            try_again = true;   // Retry with remaining frames
                        }
