#### **Inner Dispatch Loop (Lines 220-408)**

```rust
async fn dispatch_inner(
    &self,
    layer: &DispatchLayer,
    host: Host,
) -> Result<(Host, DispatchLayer), DispatchError> {
    let mut allocation_capacity = host.alloc_available_cores;
    let allocation_name = host.alloc_name.clone();
    let mut last_host_version = host;

    let allocation_service = allocation_service().await.map_err(|err| {
        DispatchError::Failure(err.wrap_err("Allocation Service is not available"))
    })?;

    // Validation closure for checking bookability
    let is_subscription_bookable = |cores_requested| {
        matches!(allocation_service.get_subscription(&allocation_name, &layer.show_id),
            Some(subscription) if subscription.bookable(&cores_requested)
        )
    };

    let mut layer = layer.clone();
    let mut last_error = None;
    let mut non_retrieable_frames = Vec::new();
    let dispatch_id = Uuid::new_v4();  // Unique ID for this dispatch attempt

    for frame in &layer.frames {
        // Lines 257-272: Calculate virtual proc and consume host resources
        let (virtual_proc, updated_host) = match Self::consume_host_virtual_resources(
            frame,
            &last_host_version,
            CONFIG.queue.memory_stranded_threshold,
        )
        .await
        {
            Ok(result) => result,
            Err(VirtualProcError::HostResourcesExtinguished(msg)) => {
                debug!(
                    "({dispatch_id}) Host resource extinguished for {}. {}",
                    last_host_version, msg
                );
                break;  // Stop trying frames on this host
            }
        };

        // Lines 280-282: Create SEPARATE transaction for each proc
        let mut proc_transaction = begin_transaction()
            .await
            .map_err(DispatchError::DbFailure)?;

        // Lines 285-289: Check layer limits before dispatching
        if !self
            .layer_dao
            .check_limits(&mut proc_transaction, &layer)
            .await
            .map_err(DispatchError::DbFailure)?
        {
            proc_transaction
                .rollback()
                .await
                .map_err(DispatchError::DbFailure)?;
            info!("({dispatch_id}) Skipping layer {}, reached limits", layer);
            break;
        }

        // Lines 301-310: Dispatch the virtual proc
        match self
            .dispatch_virtual_proc(
                dispatch_id,
                virtual_proc,
                updated_host,
                &mut proc_transaction,
                &is_subscription_bookable,
                allocation_capacity,
            )
            .await
        {
            Ok((new_host, new_allocation_capacity)) => {
                // Success: commit and track
                proc_transaction
                    .commit()
                    .await
                    .map_err(DispatchError::DbFailure)?;

                metrics::increment_frames_dispatched(&frame.show_name);

                if let Ok(elapsed) = frame.updated_at.elapsed() {
                    metrics::observe_time_to_book(elapsed);
                }

                non_retrieable_frames.push(frame.id);
                allocation_capacity = new_allocation_capacity;
                last_host_version = new_host;
            }
            Err(err) => {
                // Error: rollback and handle
                proc_transaction
                    .rollback()
                    .await
                    .map_err(DispatchError::DbFailure)?;

                match err {
                    DispatchVirtualProcError::AllocationOverBurst(err) => {
                        info!("({dispatch_id}) {frame_str} {err}");
                        last_error = Some(err);
                        break;  // Stop trying, allocation is full
                    }
                    DispatchVirtualProcError::FailedToStartOnDb(err) => {
                        // DB error: log and try next frame, but break if already had error
                        if last_error.is_some() {
                            break;
                        }
                        warn!(
                            "({dispatch_id}) Failed to start frame {} on Db. {}",
                            frame_str, err
                        );
                        last_error = Some(err);
                        // IMPORTANT: Do NOT update last_host_version here (Line 355)
                        // Transaction rolled back, so no resources were consumed
                        continue;  // Try next frame with same host state
                    }
                    DispatchVirtualProcError::FrameCouldNotBeUpdated => {
                        // Version changed: stop processing this layer
                        info!(
                            "({dispatch_id}) Frame {} couldn't be updated. Version has changed.",
                            frame_str
                        );
                        non_retrieable_frames.push(frame.id);
                        break;
                    }
                    DispatchVirtualProcError::RqdConnectionFailed { host, error } => {
                        // RQD connection broken: stop processing this host
                        warn!(
                            "({dispatch_id}) Failed to connect to rqd on {}. {:?}",
                            host, error
                        );
                        break;
                    }
                }
            }
        }
    }

    // Lines 384-407: Final logging
    if non_retrieable_frames.is_empty() {
        info!(
            "Found no frames on {} to dispatch to {}",
            layer, last_host_version
        );
    } else {
        debug!(
            "Dispatched {} frames on {}: ",
            non_retrieable_frames.len(),
            layer
        );
        for proc in &non_retrieable_frames {
            trace!("{}", proc);
        }
    }

    if !non_retrieable_frames.is_empty() {
        layer.drain_frames(non_retrieable_frames);
    }

    if let Some(error) = last_error {
        warn!("Wasn't able to dispatch all frames: {:?}", error)  // LINE 406
    }
    Ok((last_host_version, layer))
}
```

**Critical notes:**
- **Line 252:** Unique `dispatch_id` (UUID) created for logging all operations in this dispatch
- **Line 280:** NEW transaction created for EACH frame (not reusing the outer dispatch transaction)
- **Line 355:** IMPORTANT comment about not updating `last_host_version` on DB failures
- **Line 402-408:** Frames are only removed from layer if dispatch succeeds
- **Line 406:** The warning you're investigating logs if any error occurred during the loop

