    &self,
    transaction: &mut Transaction<'_, Postgres>,
    virtual_proc: &VirtualProc,
    host_id: Uuid,
    dispatch_id: Uuid,
) -> Result<UpdatedHostResources, DispatchVirtualProcError> {
