async fn update_database_for_dispatch(
    &self,
    transaction: &mut Transaction<'_, Postgres>,
    virtual_proc: &VirtualProc,
    host_id: Uuid,
    dispatch_id: Uuid,
) -> Result<UpdatedHostResources, DispatchVirtualProcError> {
    // Step 1: Update frame to RUNNING (Lines 516-526)
    self.frame_dao
