    34→    cluster_key::{ClusterKey, Tag, TagType},
    35→    config::CONFIG,
    36→    dao::HostDao,
    37→    host_cache::{messages::*, store, *},
    38→    models::{CoreSize, Host},
    39→};
    40→
    41→#[derive(Clone)]
    42→pub struct HostCacheService {
    43→    host_dao: Arc<HostDao>,
    44→    cluster_index: Arc<HashMap<ClusterKey, HostCache>>,
    45→    reserved_hosts: Arc<HashMap<HostId, HostReservation>>,
    46→    cache_hit: Arc<AtomicU64>,
    47→    cache_miss: Arc<AtomicU64>,
    48→    concurrency_semaphore: Arc<Semaphore>,
    49→}
    50→
    51→/// Use a reservation system to prevent race conditions when trying to book a host
    52→/// that belongs to multiple groups.
    53→struct HostReservation {
    54→    reserved_time: SystemTime,
    55→}
    56→
    57→impl HostReservation {
    58→    pub fn new() -> Self {
    59→        HostReservation {
    60→            reserved_time: SystemTime::now(),
    61→        }
    62→    }
    63→
    64→    pub fn expired(&self) -> bool {
    65→        self.reserved_time.elapsed().unwrap_or_default() > Duration::from_secs(10)
    66→    }
    67→}
    68→
    69→impl Actor for HostCacheService {
    70→    type Context = actix::Context<Self>;
    71→
    72→    fn started(&mut self, ctx: &mut Self::Context) {
    73→        let service_for_monitor = self.clone();
    74→        let service_for_clean_up = self.clone();
    75→
    76→        ctx.run_interval(CONFIG.host_cache.monitoring_interval, move |_act, ctx| {
    77→            let service = service_for_monitor.clone();
    78→            let actor_clone = service.clone();
    79→            ctx.spawn(async move { service.refresh_cache().await }.into_actor(&actor_clone));
    80→        });
    81→
    82→        ctx.run_interval(CONFIG.host_cache.clean_up_interval, move |_act, _ctx| {
    83→            let service = service_for_clean_up.clone();
    84→
    85→            // Clean up stale hosts from the host store
    86→            service.cleanup_stale_hosts();
    87→        });
    88→
    89→        info!("HostCacheService actor started");
    90→    }
    91→
    92→    fn stopped(&mut self, _ctx: &mut Self::Context) {
    93→        info!("HostCacheService actor stopped");
    94→    }
    95→}
    96→
    97→impl<F> Handler<CheckOut<F>> for HostCacheService
    98→where
    99→    F: Fn(&Host) -> bool + 'static,
   100→{
   101→    type Result = ResponseActFuture<Self, Result<CheckedOutHost, HostCacheError>>;
   102→
   103→    fn handle(&mut self, msg: CheckOut<F>, _ctx: &mut Self::Context) -> Self::Result {
   104→        let CheckOut {
   105→            facility_id,
   106→            show_id,
   107→            tags,
   108→            cores,
   109→            memory,
   110→            validation,
   111→        } = msg;
   112→
   113→        let service = self.clone();
   114→
   115→        Box::pin(
   116→            async move {
   117→                let out = service
   118→                    .check_out(facility_id, show_id, tags, cores, memory, validation)
   119→                    .await;
   120→                if let Ok(host) = &out {
   121→                    debug!("Checked out {}", host.1);
   122→                }
   123→                out
   124→            }
   125→            .into_actor(self)
   126→            .map(|result, _, _| result),
   127→        )
   128→    }
   129→}
   130→
   131→impl Handler<CheckIn> for HostCacheService {
   132→    type Result = ();
   133→
   134→    fn handle(&mut self, msg: CheckIn, _ctx: &mut Self::Context) -> Self::Result {
   135→        let CheckIn(cluster_key, payload) = msg;
   136→        match payload {
   137→            CheckInPayload::Host(host) => {
   138→                let host_str = format!("{}", host);
   139→                self.check_in(cluster_key, host);
   140→
   141→                debug!("Checked in {}", &host_str);
   142→            }
   143→            CheckInPayload::Invalidate(host_id) => {
   144→                let _ = self.reserved_hosts.remove_sync(&host_id);
   145→
   146→                debug!("Checked in {} (invalid)", &host_id);
   147→            }
   148→        }
   149→    }
   150→}
   151→
   152→impl Handler<CacheRatio> for HostCacheService {
   153→    type Result = CacheRatioResponse;
   154→
   155→    fn handle(&mut self, _msg: CacheRatio, _ctx: &mut Self::Context) -> Self::Result {
   156→        CacheRatioResponse {
   157→            hit: self.cache_hit.load(atomic::Ordering::Relaxed),
   158→            miss: self.cache_miss.load(atomic::Ordering::Relaxed),
   159→            hit_ratio: self.cache_hit_ratio(),
   160→        }
   161→    }
   162→}
   163→
   164→impl HostCacheService {
   165→    /// Creates a new HostCacheService with empty cache groups.
   166→    ///
   167→    /// Initializes the service with DAO access, cache tracking metrics,
   168→    /// and concurrency controls.
   169→    ///
   170→    /// # Returns
   171→    ///
   172→    /// * `Ok(HostCacheService)` - New service instance
   173→    /// * `Err(miette::Error)` - Failed to initialize dependencies
   174→    pub(in crate::host_cache) async fn new() -> Result<Self> {
   175→        Ok(HostCacheService {
   176→            host_dao: Arc::new(HostDao::new().await?),
   177→            cluster_index: Arc::new(HashMap::new()),
   178→            cache_hit: Arc::new(AtomicU64::new(0)),
   179→            cache_miss: Arc::new(AtomicU64::new(0)),
   180→            concurrency_semaphore: Arc::new(Semaphore::new(
   181→                CONFIG.host_cache.concurrent_fetch_permit,
   182→            )),
   183→            reserved_hosts: Arc::new(HashMap::new()),
   184→        })
   185→    }
   186→
   187→    /// Checks out a host from the cache that matches the requirements.
   188→    ///
   189→    /// Searches through cache groups for each tag until a suitable host is found.
   190→    /// If not found in cache, fetches from database. Implements host reservation
   191→    /// to prevent race conditions.
   192→    ///
   193→    /// # Arguments
   194→    ///
   195→    /// * `facility_id` - Facility identifier
   196→    /// * `show_id` - Show identifier
   197→    /// * `tags` - List of tags to search (tried in priority order)
   198→    /// * `cores` - Minimum cores required
   199→    /// * `memory` - Minimum memory required
   200→    /// * `validation` - Additional validation function
   201→    ///
   202→    /// # Returns
   203→    ///
   204→    /// * `Ok(CheckedOutHost)` - Host with cluster key
   205→    /// * `Err(HostCacheError)` - No suitable host found or database error
   206→    async fn check_out<F>(
   207→        &self,
   208→        facility_id: Uuid,
   209→        show_id: Uuid,
   210→        tags: Vec<Tag>,
   211→        cores: CoreSize,
   212→        memory: ByteSize,
   213→        validation: F,
   214→    ) -> Result<CheckedOutHost, HostCacheError>
   215→    where
   216→        F: Fn(&Host) -> bool,
   217→    {
   218→        let cache_keys = self.gen_cache_keys(facility_id, show_id, tags);
   219→
   220→        // Extend validation to also check for hosts that are already reserved
   221→        let validation = |host: &Host| {
   222→            let available = self
   223→                .reserved_hosts
   224→                .read_sync(&host.id, |_, reservation| reservation.expired())
   225→                .unwrap_or(true);
   226→            validation(host) && available
   227→        };
   228→
   229→        for cache_key in cache_keys {
   230→            // Attempt to read from the cache
   231→            let cached_candidate = self
   232→                .cluster_index
   233→                // Using the async counterpart here to prevent blocking during checkout.
   234→                // As the number of groups is not very large, consumers are eventually going to
   235→                // fight for the same rows.
   236→                .read_async(&cache_key, |_, cached_group| {
   237→                    if !cached_group.expired() {
   238→                        cached_group
   239→                            // Checkout host from a group
   240→                            .check_out(cores, memory, validation)
   241→                            .map(|host| (cache_key.clone(), host.clone()))
   242→                            .ok()
   243→                    } else {
   244→                        None
   245→                    }
   246→                })
   247→                .await
   248→                .flatten();
   249→
   250→            // Fetch form the database if not found on cache
   251→            match cached_candidate {
   252→                Some(cached) => {
   253→                    self.reserve_host(cached.1.id, true);
   254→                    return Ok(CheckedOutHost(cached.0, cached.1));
   255→                }
   256→                None => {
   257→                    let group = self
   258→                        .fetch_group_data(&cache_key)
   259→                        .await
   260→                        .map_err(|err| HostCacheError::FailedToQueryHostCache(err.to_string()))?;
   261→                    let checked_out_host = group
   262→                        // Checkout host from a group
   263→                        .check_out(cores, memory, validation)
   264→                        .map(|host| CheckedOutHost(cache_key.clone(), host.clone()));
   265→
   266→                    if let Ok(checked_out_host) = checked_out_host {
   267→                        self.reserve_host(checked_out_host.1.id, false);
   268→                        // Only count as a cache miss if there was a host candidate available
   269→                        return Ok(checked_out_host);
   270→                    } else {
   271→                        debug!(
   272→                            "Wasn't able to find suitable hosts for group {:?}",
   273→                            &cache_key
   274→                        );
   275→                    }
   276→                }
   277→            }
   278→        }
   279→        Err(HostCacheError::NoCandidateAvailable)
   280→    }
   281→
   282→    /// Reserves a host to prevent concurrent checkout and tracks cache metrics.
   283→    ///
   284→    /// Marks the host as reserved and updates hit/miss counters for cache
   285→    /// performance tracking.
   286→    ///
   287→    /// # Arguments
   288→    ///
   289→    /// * `host_id` - ID of the host to reserve
   290→    /// * `cache_hit` - Whether this was a cache hit (true) or miss (false)
   291→    fn reserve_host(&self, host_id: HostId, cache_hit: bool) {
   292→        if cache_hit {
   293→            self.cache_hit.fetch_add(1, atomic::Ordering::Relaxed);
   294→        } else {
   295→            self.cache_miss.fetch_add(1, atomic::Ordering::Relaxed);
   296→        }
   297→        // Mark host as reserved
   298→        let _ = self
   299→            .reserved_hosts
   300→            .insert_sync(host_id, HostReservation::new());
   301→    }
   302→
   303→    /// Returns a host to the cache group after use.
   304→    ///
   305→    /// Removes the host from reservation and adds it back to the appropriate
   306→    /// cache group. If the group has expired, the host is dropped.
   307→    ///
   308→    /// # Arguments
   309→    ///
   310→    /// * `cluster_key` - The cluster key identifying the cache group
   311→    /// * `host` - Host to return to the cache
   312→    fn check_in(&self, cluster_key: ClusterKey, host: Host) {
   313→        trace!(
   314→            "{}: Attempting to checkin ({}, {})",
   315→            cluster_key,
   316→            host.id,
   317→            host.idle_cores
   318→        );
   319→        let host_id = host.id;
   320→
   321→        match self.cluster_index.get_sync(&cluster_key) {
   322→            Some(group) => {
   323→                group.check_in(host, false);
   324→            }
   325→            None => {
   326→                info!(
   327→                    "{} checking in on unexisting group ({}).",
   328→                    host.id, cluster_key
   329→                );
   330→                // Noop. The group might have expired and will be updated on demand
   331→            }
   332→        }
   333→        let _ = self.reserved_hosts.remove_sync(&host_id);
   334→
   335→        trace!("{}: Done checkin", cluster_key);
   336→    }
   337→
   338→    /// Calculates the cache hit ratio as a percentage.
   339→    ///
   340→    /// # Returns
   341→    ///
   342→    /// * `usize` - Hit ratio percentage (0-100)
   343→    fn cache_hit_ratio(&self) -> usize {
   344→        let hit = self.cache_hit.load(atomic::Ordering::Relaxed) as f64;
   345→        let miss = self.cache_miss.load(atomic::Ordering::Relaxed) as f64;
   346→
   347→        ((hit / (hit + miss)) * 100.0) as usize
   348→    }
   349→
   350→    /// Generates cache keys from tags in priority order.
   351→    ///
   352→    /// Creates ClusterKey instances for each tag and sorts them by priority:
   353→    /// MANUAL > HOSTNAME > ALLOC. This order ensures more specific tags are
   354→    /// checked first.
   355→    ///
   356→    /// # Arguments
   357→    ///
   358→    /// * `facility_id` - Facility identifier
   359→    /// * `show_id` - Show identifier
   360→    /// * `tags` - Tags to convert to cache keys
   361→    ///
   362→    /// # Returns
   363→    ///
   364→    /// * `impl IntoIterator<Item = ClusterKey>` - Sorted cache keys
   365→    #[allow(clippy::map_entry)]
   366→    fn gen_cache_keys(
   367→        &self,
   368→        facility_id: Uuid,
   369→        show_id: Uuid,
   370→        tags: Vec<Tag>,
   371→    ) -> impl IntoIterator<Item = ClusterKey> {
   372→        tags.into_iter()
   373→            .map(|tag| ClusterKey {
   374→                facility_id,
   375→                show_id,
   376→                tag,
   377→            })
   378→            // Make sure tags are evaluated in this order:
   379→            // MANUAL -> HOSTNAME -> HARDWARE -> ALLOC
   380→            .sorted_by(|l, r| match (&l.tag.ttype, &r.tag.ttype) {
   381→                (TagType::Alloc, TagType::Alloc)
   382→                | (TagType::HostName, TagType::HostName)
   383→                | (TagType::Hardware, TagType::Hardware)
   384→                | (TagType::Manual, TagType::Manual) => Ordering::Equal,
   385→                (TagType::Manual, _) => Ordering::Less,
   386→                (TagType::HostName, _) => Ordering::Less,
   387→                (TagType::Hardware, _) => Ordering::Less,
   388→                (TagType::Alloc, _) => Ordering::Greater,
   389→            })
   390→    }
   391→
   392→    /// Periodically refreshes cache data and removes idle groups.
   393→    ///
   394→    /// Runs on a timer to update active cache groups from the database and
   395→    /// remove groups that haven't been queried recently.
   396→    async fn refresh_cache(&self) {
   397→        let caches = Arc::new(&self.cluster_index);
   398→
   399→        // Clone list of groups keys to avoid keeping a lock through the stream lifetime
   400→        let mut cloned_keys = Vec::new();
   401→        self.cluster_index.iter_sync(|key, value| {
   402→            cloned_keys.push((key.clone(), value.is_idle()));
   403→            true
   404→        });
   405→
   406→        let groups_for_removal = HashSet::new();
   407→
   408→        stream::iter(cloned_keys)
   409→            .map(|(group_key, is_idle)| {
   410→                let groups_for_removal = groups_for_removal.clone();
   411→
   412→                async move {
   413→                    // Skip groups if it exists on the cache but haven't been queried for a while
   414→                    if is_idle {
   415→                        if let Err(err) = groups_for_removal.insert_async(group_key).await {
   416→                            error!("Failed to mark group for removal on host_cache. {}", err);
   417→                        }
   418→                    } else if let Err(err) = self.fetch_group_data(&group_key).await {
   419→                        error!(
   420→                            "Failed to fetch cache data on cache loop for key {}.{}",
   421→                            group_key, err
   422→                        );
   423→                    }
   424→                }
   425→            })
   426→            .buffer_unordered(CONFIG.host_cache.concurrent_groups)
   427→            .collect::<Vec<()>>()
   428→            .await;
   429→
   430→        // Clean up caches that haven't been queried for a while
   431→        groups_for_removal.iter_sync(|key| {
   432→            caches.remove_sync(key);
   433→            true
   434→        });
   435→    }
   436→
   437→    /// Removes stale hosts from the global host store.
   438→    ///
   439→    /// This method triggers cleanup of hosts that haven't been updated within
   440→    /// the configured `host_staleness_threshold` duration. It logs the number
   441→    /// of hosts removed for monitoring purposes.
   442→    fn cleanup_stale_hosts(&self) {
   443→        let removed_count = store::HOST_STORE.cleanup_stale_hosts();
   444→        if removed_count > 0 {
   445→            info!("Cleaned up {} stale hosts from store", removed_count);
   446→        }
   447→    }
   448→
   449→    /// Fetches host data from the database and populates a cache group.
   450→    ///
   451→    /// Queries the database for hosts matching the cluster key and adds them
   452→    /// to the cache. Uses a semaphore to limit concurrent database queries.
   453→    ///
   454→    /// # Arguments
   455→    ///
   456→    /// * `key` - Cluster key identifying which hosts to fetch
   457→    ///
   458→    /// # Returns
   459→    ///
   460→    /// * `Ok(OccupiedEntry)` - Cache entry with fetched hosts
   461→    /// * `Err(miette::Error)` - Database query failed
   462→    async fn fetch_group_data(
   463→        &self,
   464→        key: &ClusterKey,
   465→    ) -> Result<OccupiedEntry<'_, ClusterKey, HostCache>> {
   466→        let _permit = self
   467→            .concurrency_semaphore
   468→            .acquire()
   469→            .await
   470→            .into_diagnostic()?;
   471→
   472→        let tag = key.tag.to_string();
   473→        let hosts = self
   474→            .host_dao
   475→            .fetch_hosts_by_show_facility_tag(key.show_id, key.facility_id, &tag)
   476→            .await
   477→            .into_diagnostic()?;
   478→
   479→        let cache = self.cluster_index.entry_sync(key.clone()).or_default();
   480→
   481→        if hosts.is_empty() {
   482→            debug!(
   483→                "Found no suitable hosts on the database for the cluster key {:?}",
   484→                key
   485→            );
   486→        }
   487→
   488→        for host in hosts {
   489→            let h: Host = host.into();
   490→            cache.check_in(h, false);
   491→        }
   492→        cache.ping_fetch();
   493→        Ok(cache)
   494→    }
   495→}
