    13→/// A cache of hosts organized in B-trees to speed up searching and traversing hosts in order.
    14→///
    15→/// Host are queried by their number of available cores and available memory. To speed up this
    16→/// search, they are stored in groups organized as the example bellow:
    17→///
    18→/// * 2-cores:
    19→///   - <= 2GB
    20→///   - > 2GB <= 4GB
    21→///   - > 4GB <= 6GB
    22→///   - > 6GB <= 8GB
    23→/// * 4-cores:
    24→///   - <= 2GB
    25→///   - > 2GB <= 4GB
    26→///   - > 4GB <= 6GB
    27→///   - > 6GB <= 8GB
    28→/// * 5-cores:
    29→///   - <= 2GB
    30→///   - > 2GB <= 4GB
    31→///   - > 4GB <= 6GB
    32→///   - > 6GB <= 8GB
    33→///
    34→/// ...
    35→use std::{
    36→    cell::RefCell,
    37→    collections::{BTreeMap, HashSet},
    38→    sync::RwLock,
    39→    time::{Duration, SystemTime},
    40→};
    41→
    42→use bytesize::ByteSize;
    43→use miette::Result;
    44→use uuid::Uuid;
    45→
    46→use crate::{
    47→    config::{HostBookingStrategy, CONFIG},
    48→    host_cache::{store::HOST_STORE, HostCacheError, HostId},
    49→    models::{CoreSize, Host},
    50→};
    51→
    52→type CoreKey = u32;
    53→type MemoryKey = u64;
    54→
    55→/// A B-Tree of Hosts ordered by memory
    56→pub type MemoryBTree = BTreeMap<MemoryKey, HashSet<HostId>>;
    57→
    58→pub struct HostCache {
    59→    /// B-Tree of host groups ordered by their number of available cores
    60→    hosts_index: RwLock<BTreeMap<CoreKey, MemoryBTree>>,
    61→    /// If a cache stops being queried for a certain amount of time, stop keeping it up to date
    62→    last_queried: RwLock<SystemTime>,
    63→    /// Marks if the data on this cache have expired
    64→    last_fetched: RwLock<Option<SystemTime>>,
    65→    strategy: HostBookingStrategy,
    66→}
    67→
    68→impl Default for HostCache {
    69→    fn default() -> Self {
    70→        HostCache {
    71→            hosts_index: RwLock::new(BTreeMap::new()),
    72→            last_queried: RwLock::new(SystemTime::now()),
    73→            last_fetched: RwLock::new(None),
    74→            strategy: CONFIG.queue.host_booking_strategy,
    75→        }
    76→    }
    77→}
    78→
    79→impl HostCache {
    80→    /// Updates the last queried timestamp to prevent cache expiration.
    81→    ///
    82→    /// Called whenever the cache is accessed to track activity and prevent
    83→    /// idle timeout expiration.
    84→    fn ping_query(&self) {
    85→        let mut lock = self
    86→            .last_queried
    87→            .write()
    88→            .unwrap_or_else(|poisoned| poisoned.into_inner());
    89→        *lock = SystemTime::now();
    90→    }
    91→
    92→    /// Updates the last fetched timestamp to mark cache data as fresh.
    93→    ///
    94→    /// Called after fetching new data from the database to mark when the
    95→    /// cache was last refreshed.
    96→    pub fn ping_fetch(&self) {
    97→        let mut lock = self
    98→            .last_fetched
    99→            .write()
   100→            .unwrap_or_else(|poisoned| poisoned.into_inner());
   101→        *lock = Some(SystemTime::now());
   102→    }
   103→
   104→    /// Checks if the cache data has expired and needs refreshing.
   105→    ///
   106→    /// Cache expires after the configured group_idle_timeout period has elapsed
   107→    /// since the last fetch.
   108→    ///
   109→    /// # Returns
   110→    ///
   111→    /// * `bool` - True if cache data has expired
   112→    pub fn expired(&self) -> bool {
   113→        let lock = self
   114→            .last_fetched
   115→            .read()
   116→            .unwrap_or_else(|poisoned| poisoned.into_inner());
   117→        matches!(*lock,
   118→            Some(last_fetched)
   119→                if last_fetched.elapsed().unwrap_or(Duration::from_secs(1))
   120→                > CONFIG.host_cache.group_idle_timeout)
   121→    }
   122→
   123→    /// Checks if the cache has been idle for too long without queries.
   124→    ///
   125→    /// Used to determine if a cache group should be removed to save memory.
   126→    ///
   127→    /// # Returns
   128→    ///
   129→    /// * `bool` - True if cache hasn't been queried within the idle timeout period
   130→    pub fn is_idle(&self) -> bool {
   131→        self.last_queried
   132→            .read()
   133→            .unwrap_or_else(|poisoned| poisoned.into_inner())
   134→            .elapsed()
   135→            .unwrap_or(Duration::from_secs(1))
   136→            > CONFIG.host_cache.group_idle_timeout
   137→    }
   138→
   139→    /// Checks out the best matching host from the cache.
   140→    ///
   141→    /// Finds a host with sufficient resources that passes the validation function,
   142→    /// removes it from the cache, and returns it. The host must be checked back in
   143→    /// after use.
   144→    ///
   145→    /// # Arguments
   146→    ///
   147→    /// * `cores` - Minimum number of cores required
   148→    /// * `memory` - Minimum memory required
   149→    /// * `validation` - Function to validate additional host requirements
   150→    ///
   151→    /// # Returns
   152→    ///
   153→    /// * `Ok(Host)` - Successfully checked out host
   154→    /// * `Err(HostCacheError)` - No suitable host available
   155→    pub fn check_out<F>(
   156→        &self,
   157→        cores: CoreSize,
   158→        memory: ByteSize,
   159→        validation: F,
   160→    ) -> Result<Host, HostCacheError>
   161→    where
   162→        F: Fn(&Host) -> bool,
   163→    {
   164→        self.ping_query();
   165→
   166→        let host = self
   167→            .remove_host(cores, memory, validation)
   168→            .ok_or(HostCacheError::NoCandidateAvailable)?;
   169→
   170→        Ok(host)
   171→    }
   172→
   173→    /// Removes a suitable host from the cache based on resource requirements.
   174→    ///
   175→    /// Searches for a host with at least the requested cores and memory that
   176→    /// passes the validation function. Uses atomic operations with retry logic
   177→    /// to prevent race conditions where host state changes between lookup and removal.
   178→    ///
   179→    /// # Arguments
   180→    ///
   181→    /// * `cores` - Minimum number of cores required
   182→    /// * `memory` - Minimum memory required
   183→    /// * `validation` - Function to validate additional requirements
   184→    ///
   185→    /// # Returns
   186→    ///
   187→    /// * `Some(Host)` - Host that meets all requirements
   188→    /// * `None` - No suitable host found
   189→    fn remove_host<F>(&self, cores: CoreSize, memory: ByteSize, validation: F) -> Option<Host>
   190→    where
   191→        F: Fn(&Host) -> bool,
   192→    {
   193→        let core_key = cores.value() as u32;
   194→        let memory_key = Self::gen_memory_key(memory);
   195→
   196→        let failed_candidates: RefCell<Vec<Uuid>> = RefCell::new(Vec::new());
   197→        let host_validation = |host: &Host| {
   198→            // Check caller validation
   199→            validation(host) &&
   200→            // Check memory and core requirements just in case
   201→            host.idle_memory >= memory &&
   202→            host.idle_cores >= cores &&
   203→            // Ensure we're not retrying the same host as last attempts
   204→            !failed_candidates.borrow().contains(&host.id)
   205→        };
   206→
   207→        let mut attempts = 5;
   208→        loop {
   209→            // Step 1: Find a candidate host in the index
   210→            let candidate_info = {
   211→                let host_index_lock = self.hosts_index.read().unwrap_or_else(|p| p.into_inner());
   212→                let mut iter: Box<dyn Iterator<Item = (&CoreKey, &MemoryBTree)>> =
   213→                    if !self.strategy.core_saturation {
   214→                        // Reverse order to find hosts with max amount of cores available
   215→                        Box::new(host_index_lock.range(core_key..).rev())
   216→                    } else {
   217→                        Box::new(host_index_lock.range(core_key..))
   218→                    };
   219→
   220→                iter.find_map(|(by_core_key, hosts_by_memory)| {
   221→                    let find_fn = |(by_memory_key, hosts): (&u64, &HashSet<Uuid>)| {
   222→                        hosts.iter().find_map(|host_id| {
   223→                            HOST_STORE.get(host_id).and_then(|host| {
   224→                                // Check validation and memory capacity
   225→                                if host_validation(&host) {
   226→                                    Some((
   227→                                        *by_core_key,
   228→                                        *by_memory_key,
   229→                                        *host_id,
   230→                                        host.last_updated,
   231→                                    ))
   232→                                } else {
   233→                                    None
   234→                                }
   235→                            })
   236→                        })
   237→                    };
   238→
   239→                    if self.strategy.memory_saturation {
   240→                        // Search for hosts with at least the same amount of memory requested
   241→                        hosts_by_memory.range(memory_key..).find_map(find_fn)
   242→                    } else {
   243→                        // Search for hosts with the most amount of memory available
   244→                        hosts_by_memory.range(memory_key..).rev().find_map(find_fn)
   245→                    }
   246→                })
   247→            };
   248→
   249→            // Step 2: Attempt atomic removal if we found a candidate
   250→            if let Some((by_core_key, by_memory_key, host_id, expected_last_updated)) =
   251→                candidate_info
   252→            {
   253→                // Atomic check-and-remove from HOST_STORE
   254→                // Ensure host is still valid when it's time to remove it
   255→                match HOST_STORE.atomic_remove_if_valid(
   256→                    &host_id,
   257→                    expected_last_updated,
   258→                    host_validation,
   259→                ) {
   260→                    Ok(Some(removed_host)) => {
   261→                        // Successfully removed from store, now remove from index
   262→                        let mut host_index_lock =
   263→                            self.hosts_index.write().unwrap_or_else(|p| p.into_inner());
   264→
   265→                        // Remove from hosts_by_core_and_memory index
   266→                        host_index_lock
   267→                            .get_mut(&by_core_key)
   268→                            .and_then(|hosts_by_memory| hosts_by_memory.get_mut(&by_memory_key))
   269→                            .map(|hosts| hosts.remove(&host_id));
   270→
   271→                        return Some(removed_host);
   272→                    }
   273→                    Ok(None) | Err(()) => {
   274→                        // Host was removed by another thread. Try another candidate
   275→                        attempts -= 1;
   276→                        // Mark the failed candidate to avoid retrying it again.
   277→                        failed_candidates.borrow_mut().push(host_id);
   278→                        if attempts <= 0 {
   279→                            break;
   280→                        }
   281→                    }
   282→                }
   283→            } else {
   284→                break;
   285→            }
   286→        }
   287→
   288→        None
   289→    }
   290→
   291→    /// Returns a host to the cache after use.
   292→    ///
   293→    /// Updates the cache with the host's current resource state. If the host
   294→    /// already exists in the cache, it's updated with the new values. The host
   295→    /// is indexed by its current idle cores and memory for efficient lookup.
   296→    ///
   297→    /// This method now performs all updates atomically under a single write lock,
   298→    /// preventing race conditions with concurrent check_out operations.
   299→    ///
   300→    /// # Arguments
   301→    ///
   302→    /// * `host` - Host to return to the cache
   303→    pub fn check_in(&self, host: Host, authoritative: bool) {
   304→        let host_id = host.id;
   305→
   306→        // Update the data_store with new version
   307→        let last_host_version = HOST_STORE.insert(host, authoritative);
   308→
   309→        let core_key = last_host_version.idle_cores.value() as CoreKey;
   310→        let memory_key = Self::gen_memory_key(last_host_version.idle_memory);
   311→
   312→        let mut host_index = self
   313→            .hosts_index
   314→            .write()
   315→            .unwrap_or_else(|poisoned| poisoned.into_inner());
   316→
   317→        // Insert at the new location
   318→        host_index
   319→            .entry(core_key)
   320→            .or_default()
   321→            .entry(memory_key)
   322→            .or_default()
   323→            .insert(host_id);
   324→    }
   325→
   326→    /// Generates a memory key for cache indexing by bucketing memory values.
   327→    ///
   328→    /// Divides memory by the configured divisor to group hosts with similar
   329→    /// memory into the same bucket, reducing cache fragmentation.
   330→    ///
   331→    /// # Arguments
   332→    ///
   333→    /// * `memory` - Memory amount to convert to a key
   334→    ///
   335→    /// # Returns
   336→    ///
   337→    /// * `MemoryKey` - Bucketed memory key for indexing
   338→    fn gen_memory_key(memory: ByteSize) -> MemoryKey {
   339→        memory.as_u64() / CONFIG.host_cache.memory_key_divisor.as_u64()
   340→    }
   341→}
