    20→use crate::cluster::{Cluster, ClusterFeed};
    21→
    22→use super::dao::{InstanceRow, OrchestratorDao};
    23→
    24→/// Snapshot of an instance's jobs_queried value at a point in time,
    25→/// used to compute the rate between distribution cycles.
    26→struct RateSnapshot {
    27→    jobs_queried: f64,
    28→    timestamp: Instant,
    29→}
    30→
    31→/// The distributor runs on the leader instance. It loads all clusters from the database,
    32→/// reads live instances, computes load rates, and assigns clusters to instances.
    33→pub struct Distributor {
    34→    /// Previous snapshots of each instance's jobs_queried counter, keyed by instance ID.
    35→    previous_snapshots: HashMap<Uuid, RateSnapshot>,
    36→}
    37→
    38→impl Distributor {
    39→    /// Creates a new distributor with empty rate snapshots.
    40→    ///
    41→    /// The first distribution cycle will use count-based balancing since no
    42→    /// previous rate data is available.
    43→    pub fn new() -> Self {
    44→        Distributor {
    45→            previous_snapshots: HashMap::new(),
    46→        }
    47→    }
    48→
    49→    /// Runs one distribution cycle: loads clusters, reads instances, computes assignments.
    50→    ///
    51→    /// Cleans up dead instances, loads all clusters from the database, reads live
    52→    /// instances, computes job query rates, determines optimal cluster-to-instance
    53→    /// assignments, and applies changes to the database.
    54→    ///
    55→    /// # Arguments
    56→    ///
    57→    /// * `dao` - Database access for reading instances and writing assignments
    58→    /// * `ignore_tags` - Allocation tags to exclude from cluster loading
    59→    /// * `failure_threshold` - Duration after which an instance without a heartbeat is considered dead
    60→    ///
    61→    /// # Returns
    62→    ///
    63→    /// * `Ok(())` - Distribution cycle completed successfully
    64→    /// * `Err(miette::Error)` - Database error during distribution
    65→    pub async fn distribute(
    66→        &mut self,
    67→        dao: &OrchestratorDao,
    68→        ignore_tags: &[String],
    69→        failure_threshold: Duration,
    70→    ) -> Result<()> {
    71→        // Clean up dead instances (cascade deletes their assignments)
    72→        let dead = dao
    73→            .delete_dead_instances(failure_threshold)
    74→            .await
    75→            .into_diagnostic()?;
    76→        if !dead.is_empty() {
    77→            info!("Removed {} dead instance(s): {:?}", dead.len(), dead);
    78→            // Clean snapshots for dead instances
    79→            for id in &dead {
    80→                self.previous_snapshots.remove(id);
    81→            }
    82→        }
    83→
    84→        // Load all clusters from the database
    85→        let all_clusters = ClusterFeed::load_clusters(None, ignore_tags, None).await?;
    86→
    87→        if all_clusters.is_empty() {
    88→            debug!("No clusters found in database");
    89→            return Ok(());
    90→        }
    91→
    92→        // Read live instances
    93→        let instances = dao
    94→            .get_live_instances(failure_threshold)
    95→            .await
    96→            .into_diagnostic()?;
    97→
    98→        if instances.is_empty() {
    99→            warn!("No live instances available for cluster distribution");
   100→            return Ok(());
   101→        }
   102→
   103→        // Read current assignments (cluster_json -> instance_id)
   104→        let current_assignments = dao.get_all_assignments().await.into_diagnostic()?;
   105→
   106→        // Compute job query rates per instance (enriches instances with their rate)
   107→        let rated_instances = self.compute_rates(instances);
   108→
   109→        // Compute new assignments
   110→        let new_assignments =
   111→            Self::compute_assignments(&all_clusters, &rated_instances, &current_assignments);
   112→
   113→        // Apply assignment changes to the database
   114→        self.apply_assignments(dao, &all_clusters, &new_assignments, &current_assignments)
   115→            .await?;
   116→
   117→        // Update metrics
   118→        crate::metrics::set_orchestrator_instances_alive(rated_instances.len());
   119→        crate::metrics::increment_orchestrator_rebalance();
   120→
   121→        debug!(
   122→            "Distribution complete: {} clusters across {} instances",
   123→            all_clusters.len(),
   124→            rated_instances.len()
   125→        );
   126→
   127→        Ok(())
   128→    }
   129→
   130→    /// Computes the job query rate for each instance based on the delta from previous snapshots.
   131→    /// Returns a map of instance_id -> (InstanceRow, rate) where rate is jobs/second.
   132→    /// If no previous snapshot exists (bootstrap), rate is 0.0.
   133→    fn compute_rates(
   134→        &mut self,
   135→        instances: HashMap<Uuid, InstanceRow>,
   136→    ) -> HashMap<Uuid, (InstanceRow, f64)> {
   137→        let now = Instant::now();
   138→        let mut rated_instances = HashMap::new();
   139→
   140→        for (id, instance) in instances {
   141→            let rate = if let Some(prev) = self.previous_snapshots.get(&id) {
   142→                let delta_jobs = instance.float_jobs_queried - prev.jobs_queried;
   143→                let delta_secs = now.duration_since(prev.timestamp).as_secs_f64();
   144→                if delta_secs > 0.0 && delta_jobs >= 0.0 {
   145→                    delta_jobs / delta_secs
   146→                } else {
   147→                    0.0
   148→                }
   149→            } else {
   150→                // No previous snapshot — bootstrap with rate 0
   151→                0.0
   152→            };
   153→
   154→            // Update snapshots for next cycle
   155→            self.previous_snapshots.insert(
   156→                id,
   157→                RateSnapshot {
   158→                    jobs_queried: instance.float_jobs_queried,
   159→                    timestamp: Instant::now(),
   160→                },
   161→            );
   162→            rated_instances.insert(id, (instance, rate));
   163→        }
   164→
   165→        rated_instances
   166→    }
   167→
   168→    /// Pure function that computes the optimal cluster-to-instance assignment.
   169→    ///
   170→    /// Strategy:
   171→    /// 1. Preserve stable assignments (cluster stays on same live instance if eligible).
   172→    /// 2. Assign unassigned clusters to the instance with the lowest load ratio.
   173→    fn compute_assignments(
   174→        all_clusters: &[Cluster],
   175→        rated_instances: &HashMap<Uuid, (InstanceRow, f64)>,
   176→        current_map: &HashMap<String, Uuid>,
   177→    ) -> HashMap<String, Uuid> {
   178→        let mut assignments: HashMap<String, Uuid> = HashMap::new();
   179→
   180→        // Collect instance IDs
   181→        let instance_ids: Vec<Uuid> = rated_instances.keys().copied().collect();
   182→
   183→        // Track load per instance (weighted by rate / capacity)
   184→        let mut instance_load: HashMap<Uuid, f64> = instance_ids
   185→            .iter()
   186→            .map(|id| (*id, rated_instances.get(id).map_or(0.0, |(_, rate)| *rate)))
   187→            .collect();
   188→
   189→        // Track assignment count per instance for bootstrap (when all rates are 0)
   190→        let mut instance_count: HashMap<Uuid, usize> =
   191→            instance_ids.iter().map(|id| (*id, 0)).collect();
   192→
   193→        let all_rates_zero = rated_instances.values().all(|(_, rate)| *rate == 0.0);
   194→
   195→        // Build instance capacity map
   196→        let capacity_map: HashMap<Uuid, f64> = rated_instances
   197→            .iter()
   198→            .map(|(&id, (inst, _))| (id, inst.int_capacity as f64))
   199→            .collect();
   200→
   201→        // Build facility map for affinity filtering
   202→        let instance_facilities: HashMap<Uuid, Option<String>> = rated_instances
   203→            .iter()
   204→            .map(|(&id, (inst, _))| (id, inst.str_facility.clone()))
   205→            .collect();
   206→
   207→        // First pass: preserve stable assignments
   208→        for cluster in all_clusters {
   209→            let cluster_json = serde_json::to_string(cluster).expect("Failed to serialize Cluster");
   210→
   211→            if let Some(&current_instance) = current_map.get(&cluster_json) {
   212→                if rated_instances.contains_key(&current_instance)
   213→                    && Self::is_facility_eligible(cluster, &instance_facilities, current_instance)
   214→                {
   215→                    assignments.insert(cluster_json, current_instance);
   216→                    if let Some(count) = instance_count.get_mut(&current_instance) {
   217→                        *count += 1;
   218→                    }
   219→                }
   220→            }
   221→        }
   222→
   223→        // Second pass: assign unassigned clusters
   224→        for cluster in all_clusters {
   225→            let cluster_json = serde_json::to_string(cluster).expect("Failed to serialize Cluster");
   226→
   227→            if assignments.contains_key(&cluster_json) {
   228→                continue; // Already assigned in first pass
   229→            }
   230→
   231→            // Find eligible instances for this cluster's facility
   232→            let eligible: Vec<Uuid> = instance_ids
   233→                .iter()
   234→                .filter(|id| Self::is_facility_eligible(cluster, &instance_facilities, **id))
   235→                .copied()
   236→                .collect();
   237→
   238→            if eligible.is_empty() {
   239→                warn!(
   240→                    "No eligible instance for cluster {} (facility_id={})",
   241→                    cluster, cluster.facility_id
   242→                );
   243→                continue;
   244→            }
   245→
   246→            // Pick the instance with the lowest load
   247→            let best = if all_rates_zero {
   248→                // Bootstrap: distribute by count / capacity
   249→                *eligible
   250→                    .iter()
   251→                    .min_by(|a, b| {
   252→                        let ratio_a = *instance_count.get(a).unwrap_or(&0) as f64
   253→                            / capacity_map.get(a).unwrap_or(&1.0);
   254→                        let ratio_b = *instance_count.get(b).unwrap_or(&0) as f64
   255→                            / capacity_map.get(b).unwrap_or(&1.0);
   256→                        ratio_a
   257→                            .partial_cmp(&ratio_b)
   258→                            .unwrap_or(std::cmp::Ordering::Equal)
   259→                    })
   260→                    .unwrap()
   261→            } else {
   262→                // Rate-based: pick instance with lowest rate/capacity ratio
   263→                *eligible
   264→                    .iter()
   265→                    .min_by(|a, b| {
   266→                        let ratio_a = instance_load.get(a).unwrap_or(&0.0)
   267→                            / capacity_map.get(a).unwrap_or(&1.0);
   268→                        let ratio_b = instance_load.get(b).unwrap_or(&0.0)
   269→                            / capacity_map.get(b).unwrap_or(&1.0);
   270→                        ratio_a
   271→                            .partial_cmp(&ratio_b)
   272→                            .unwrap_or(std::cmp::Ordering::Equal)
   273→                    })
   274→                    .unwrap()
   275→            };
   276→
   277→            assignments.insert(cluster_json, best);
   278→            if let Some(count) = instance_count.get_mut(&best) {
   279→                *count += 1;
   280→            }
   281→            // For rate-based distribution, slightly increase load estimate for
   282→            // subsequent assignments within the same cycle
   283→            if let Some(load) = instance_load.get_mut(&best) {
   284→                *load += 1.0;
   285→            }
   286→        }
   287→
   288→        assignments
   289→    }
   290→
   291→    /// Checks whether a cluster is eligible to run on a given instance based on facility.
   292→    fn is_facility_eligible(
   293→        cluster: &Cluster,
   294→        instance_facilities: &HashMap<Uuid, Option<String>>,
   295→        instance_id: Uuid,
   296→    ) -> bool {
   297→        match instance_facilities.get(&instance_id) {
   298→            Some(Some(facility)) => {
   299→                // Instance is scoped to a facility — cluster must match
   300→                cluster.facility_id.to_string().to_lowercase() == facility.to_lowercase()
   301→            }
   302→            _ => {
   303→                // Instance has no facility scope — accepts all clusters
   304→                true
   305→            }
   306→        }
   307→    }
   308→
   309→    /// Applies the computed assignments to the database.
   310→    /// Upserts new/changed assignments and deletes removed ones.
   311→    async fn apply_assignments(
   312→        &self,
   313→        dao: &OrchestratorDao,
   314→        all_clusters: &[Cluster],
   315→        new_assignments: &HashMap<String, Uuid>,
   316→        current_map: &HashMap<String, Uuid>,
   317→    ) -> Result<()> {
   318→        // Upsert assignments that are new or changed
   319→        for cluster in all_clusters {
   320→            let cluster_json = serde_json::to_string(cluster).expect("Failed to serialize Cluster");
   321→
   322→            if let Some(&new_instance) = new_assignments.get(&cluster_json) {
   323→                let needs_upsert = match current_map.get(&cluster_json) {
   324→                    Some(&current_instance) => current_instance != new_instance,
   325→                    None => true,
   326→                };
   327→
   328→                if needs_upsert {
   329→                    dao.upsert_assignment(new_instance, cluster)
   330→                        .await
   331→                        .into_diagnostic()?;
   332→                    debug!("Assigned cluster {} to instance {}", cluster, new_instance);
   333→                }
   334→            }
   335→        }
   336→
   337→        // Delete assignments for clusters that no longer exist in the database
   338→        for cluster_json in current_map.keys() {
   339→            if !new_assignments.contains_key(cluster_json) {
   340→                // This cluster no longer exists — try to parse and delete
   341→                if let Ok(cluster) = serde_json::from_str::<Cluster>(cluster_json) {
   342→                    dao.delete_assignment_by_cluster(&cluster)
   343→                        .await
   344→                        .into_diagnostic()?;
   345→                    debug!("Removed stale assignment for cluster {}", cluster);
   346→                }
   347→            }
   348→        }
   349→
   350→        Ok(())
   351→    }
   352→}
