    87→                // or pass the transaction through the message. For now, we'll create a new transaction
    88→                // within the dispatcher's database operations.
    89→
    90→                // Create a database transaction scope
    91→                let mut transaction = begin_transaction()
    92→                    .await
    93→                    .map_err(DispatchError::DbFailure)?;
    94→
    95→                match dispatcher.dispatch(&layer, host, &mut transaction).await {
    96→                    Ok((updated_host, updated_layer)) => {
    97→                        // Commit the transaction
    98→                        transaction
    99→                            .commit()
   100→                            .await
   101→                            .map_err(DispatchError::DbFailure)?;
