    30→/// Main entry point for orchestrated mode.
    31→///
    32→/// Sets up instance registration, heartbeat, leader election, cluster sync,
    33→/// and then runs the scheduling pipeline. On shutdown (SIGTERM/SIGINT),
    34→/// gracefully drains and deregisters.
    35→///
    36→/// # Arguments
    37→///
    38→/// * `facility` - Optional facility name to scope this instance to a specific facility
    39→/// * `ignore_tags` - Allocation tags to exclude from cluster loading
    40→///
    41→/// # Returns
    42→///
    43→/// * `Ok(())` - Scheduler completed successfully
    44→/// * `Err(miette::Error)` - Fatal error during setup or pipeline execution
    45→pub async fn run(facility: Option<String>, ignore_tags: Vec<String>) -> Result<()> {
    46→    // Shutdown signal: send `true` to stop all loops
    47→    let (shutdown_tx, shutdown_rx) = watch::channel(false);
    48→
    49→    // 1. Register this instance
    50→    let instance_mgr = InstanceManager::new(facility).await?;
    51→    instance_mgr.register().await?;
    52→
    53→    info!(
    54→        instance_id = %instance_mgr.instance_id,
    55→        "Starting orchestrated mode"
    56→    );
    57→
    58→    // 2. Create an empty ClusterFeed — clusters will be populated by the sync loop
    59→    let cluster_feed = ClusterFeed::empty();
    60→
    61→    // 3. Start heartbeat loop
    62→    let heartbeat_handle = instance_mgr.start_heartbeat(shutdown_rx.clone());
    63→
    64→    // 4. Start leader election + distribution loop
    65→    let leader_election = LeaderElection::new(instance_mgr.dao().clone());
    66→    let leader_handle = leader_election.start(ignore_tags, shutdown_rx.clone());
    67→
    68→    // 5. Start cluster sync loop (worker side)
    69→    let sync_handle = ClusterSync::start(
    70→        instance_mgr.instance_id,
    71→        instance_mgr.dao().clone(),
    72→        cluster_feed.clone(),
    73→        shutdown_rx.clone(),
    74→    );
    75→
    76→    // 6. Set up SIGTERM/SIGINT handler for graceful shutdown
    77→    let shutdown_tx_clone = shutdown_tx.clone();
    78→    let shutdown_handle = tokio::spawn(async move {
    79→        tokio::signal::ctrl_c()
    80→            .await
    81→            .expect("Failed to listen for ctrl-c");
    82→        info!("Received shutdown signal");
    83→        let _ = shutdown_tx_clone.send(true);
    84→    });
    85→
    86→    // 7. Run the pipeline — this blocks until the feed is stopped
    87→    let pipeline_result = crate::pipeline::run(cluster_feed).await;
    88→
    89→    // 8. Graceful shutdown sequence
    90→    info!("Pipeline stopped, initiating shutdown...");
    91→    let _ = shutdown_tx.send(true);
    92→
    93→    // Wait for background tasks with a timeout
    94→    let timeout = CONFIG.orchestrator.shutdown_timeout;
    95→    let _ = tokio::time::timeout(timeout, async {
    96→        let _ = heartbeat_handle.await;
    97→        let _ = leader_handle.await;
    98→        let _ = sync_handle.await;
    99→    })
   100→    .await;
   101→
   102→    // Deregister this instance
   103→    instance_mgr.shutdown().await;
   104→
   105→    shutdown_handle.abort();
   106→
   107→    pipeline_result
   108→}
