    25→/// Well-known advisory lock ID for the orchestrator leader.
    26→/// "OpenCue" encoded as hex digits: 0x4F70656E437565
    27→const ORCHESTRATOR_LOCK_ID: i64 = 0x4F70656E437565;
    28→
    29→/// Manages leader election via PostgreSQL advisory locks and runs the distribution
    30→/// loop when this instance is the leader.
    31→pub struct LeaderElection {
    32→    dao: Arc<OrchestratorDao>,
    33→    is_leader: Arc<AtomicBool>,
    34→}
    35→
    36→impl LeaderElection {
    37→    /// Creates a new leader election manager.
    38→    ///
    39→    /// # Arguments
    40→    ///
    41→    /// * `dao` - Shared orchestrator DAO for advisory lock operations
    42→    pub fn new(dao: Arc<OrchestratorDao>) -> Self {
    43→        LeaderElection {
    44→            dao,
    45→            is_leader: Arc::new(AtomicBool::new(false)),
    46→        }
    47→    }
    48→
    49→    /// Returns whether this instance is currently the leader.
    50→    #[allow(dead_code)]
    51→    pub fn is_leader(&self) -> bool {
    52→        self.is_leader.load(Ordering::Relaxed)
    53→    }
    54→
    55→    /// Returns a cloned `Arc<AtomicBool>` that reflects the current leader status.
    56→    ///
    57→    /// Useful for sharing the leader flag with other tasks that need to check
    58→    /// leadership without holding a reference to the `LeaderElection` struct.
    59→    #[allow(dead_code)]
    60→    pub fn is_leader_flag(&self) -> Arc<AtomicBool> {
    61→        self.is_leader.clone()
    62→    }
    63→
    64→    /// Starts the leader election and distribution loop.
    65→    ///
    66→    /// Continuously tries to acquire the advisory lock. Once acquired, runs the
    67→    /// distributor loop. If the lock is lost (e.g., PG connection drops), demotes
    68→    /// self and re-enters election.
    69→    ///
    70→    /// # Arguments
    71→    ///
    72→    /// * `ignore_tags` - Allocation tags to exclude from cluster loading during distribution
    73→    /// * `shutdown` - Watch receiver that signals when the loop should stop
    74→    ///
    75→    /// # Returns
    76→    ///
    77→    /// A `JoinHandle` for the spawned election/distribution task.
    78→    pub fn start(
    79→        &self,
    80→        ignore_tags: Vec<String>,
    81→        mut shutdown: watch::Receiver<bool>,
    82→    ) -> JoinHandle<()> {
    83→        let dao = self.dao.clone();
    84→        let is_leader = self.is_leader.clone();
    85→        let election_interval = CONFIG.orchestrator.election_interval;
    86→        let distribution_interval = CONFIG.orchestrator.distribution_interval;
    87→        let failure_threshold = CONFIG.orchestrator.failure_threshold;
    88→
    89→        tokio::spawn(async move {
    90→            let mut distributor = Distributor::new();
    91→
    92→            loop {
    93→                // Check for shutdown
    94→                if *shutdown.borrow() {
    95→                    info!("Leader election loop shutting down");
    96→                    break;
    97→                }
    98→
    99→                if is_leader.load(Ordering::Relaxed) {
   100→                    // We are the leader — run one distribution cycle
   101→                    match distributor
   102→                        .distribute(&dao, &ignore_tags, failure_threshold)
   103→                        .await
   104→                    {
   105→                        Ok(()) => {}
   106→                        Err(e) => {
   107→                            error!("Distribution cycle failed: {}", e);
   108→                            // If distribution fails, it might be a DB issue.
   109→                            // Demote and re-enter election after interval.
   110→                            is_leader.store(false, Ordering::Relaxed);
   111→                            warn!("Demoted from leader due to distribution failure");
   112→                            crate::metrics::set_orchestrator_is_leader(false);
   113→                        }
   114→                    }
   115→
   116→                    // Wait for next distribution cycle or shutdown
   117→                    tokio::select! {
   118→                        _ = tokio::time::sleep(distribution_interval) => {}
   119→                        _ = shutdown.changed() => {
   120→                            info!("Leader loop received shutdown signal");
   121→                            break;
   122→                        }
   123→                    }
   124→                } else {
   125→                    // Not leader — try to acquire the lock
   126→                    match dao.try_acquire_leader_lock(ORCHESTRATOR_LOCK_ID).await {
   127→                        Ok(true) => {
   128→                            info!("Acquired leader lock — this instance is now the leader");
   129→                            is_leader.store(true, Ordering::Relaxed);
   130→                            crate::metrics::set_orchestrator_is_leader(true);
   131→                            // Reset distributor state for fresh snapshots
   132→                            distributor = Distributor::new();
   133→                        }
   134→                        Ok(false) => {
   135→                            // Another instance holds the lock
   136→                        }
   137→                        Err(e) => {
   138→                            warn!("Failed to attempt leader lock acquisition: {}", e);
   139→                        }
   140→                    }
   141→
   142→                    // Wait before retrying election or shutdown
   143→                    tokio::select! {
   144→                        _ = tokio::time::sleep(election_interval) => {}
   145→                        _ = shutdown.changed() => {
   146→                            info!("Election loop received shutdown signal");
   147→                            break;
   148→                        }
   149→                    }
   150→                }

