    97→    /// Starts the heartbeat loop.
    98→    ///
    99→    /// Spawns a background task that periodically updates this instance's heartbeat
   100→    /// timestamp and jobs_queried counter in the database. Runs until the shutdown
   101→    /// signal is received.
   102→    ///
   103→    /// # Arguments
   104→    ///
   105→    /// * `shutdown` - Watch receiver that signals when the loop should stop
   106→    ///
   107→    /// # Returns
   108→    ///
   109→    /// A `JoinHandle` for the spawned heartbeat task.
   110→    pub fn start_heartbeat(&self, mut shutdown: watch::Receiver<bool>) -> JoinHandle<()> {
   111→        let instance_id = self.instance_id;
   112→        let dao = self.dao.clone();
   113→        let interval = CONFIG.orchestrator.heartbeat_interval;
   114→
   115→        tokio::spawn(async move {
   116→            let mut ticker = tokio::time::interval(interval);
   117→            loop {
   118→                tokio::select! {
   119→                    _ = ticker.tick() => {
   120→                        let jobs_queried = JOBS_QUERIED_TOTAL.get();
   121→                        if let Err(e) = dao.update_heartbeat(instance_id, jobs_queried).await {
   122→                            error!(instance_id = %instance_id, "Failed to update heartbeat: {}", e);
   123→                        }
   124→                    }
   125→                    _ = shutdown.changed() => {
   126→                        info!(instance_id = %instance_id, "Heartbeat loop shutting down");
   127→                        break;
   128→                    }
   129→                }
   130→            }
   131→        })
   132→    }
