   138→        if let Err(e) = self.dao.set_draining(self.instance_id).await {
   139→            warn!(instance_id = %self.instance_id, "Failed to set draining: {}", e);
   140→        }
   141→
   142→        if let Err(e) = self.dao.delete_instance(self.instance_id).await {
   143→            warn!(instance_id = %self.instance_id, "Failed to delete instance: {}", e);
   144→        }
   145→
   146→        info!(instance_id = %self.instance_id, "Instance deregistered");
   147→    }
