   102→    /// Processes a dispatch job by finding and dispatching its eligible layers.
   103→    ///
   104→    /// For each layer in the job:
   105→    /// - Queries eligible layers from the database
   106→    /// - Attempts to find suitable host candidates
   107→    /// - Dispatches frames to available hosts, layer by layer
   108→    ///
   109→    /// # Arguments
   110→    ///
   111→    /// * `job` - The dispatch job containing layers to process
   112→    pub async fn process(&self, job: DispatchJob) {
   113→        let job_disp = format!("{}", job);
   114→        let cluster = Arc::new(job.source_cluster);
   115→
   116→        let layers = self
   117→            .layer_dao
   118→            .query_layers(
   119→                job.id,
   120→                cluster.tags.iter().map(|tag| &tag.name).cloned().collect(),
   121→            )
   122→            .await;
   123→
   124→        match layers {
   125→            Ok(layers) => {
   126→                let processed_layers = AtomicUsize::new(0);
   127→
   128→                // Stream elegible layers from this job and dispatch one by one
   129→                for layer in layers {
   130→                    let layer_disp = format!("{}", layer);
   131→                    // Limiting the concurrency here is necessary to avoid consuming the entire
   132→                    // database connection pool
   133→                    let _permit = self
   134→                        .concurrency_semaphore
   135→                        .acquire()
   136→                        .await
   137→                        .expect("Semaphore shouldn't be closed");
   138→
   139→                    let cluster = cluster.clone();
   140→
   141→                    // Holding a permit for a layer is intended to eliminate a race condition
   142→                    // between concurrent cluster_rounds attempting to process the same layer.
   143→                    // The race condition is mitigated, but not complitely avoided, as the permit
   144→                    // is acquired after the layers and frames have been queried. Acquiring the
   145→                    // permit before querying would require breaking 'query_layers' into separate
   146→                    // queries, one per layer, which greatly impacts performance. The rare cases
   147→                    // that race each other are controlled by the frame.int_version lock on
   148→                    // frame_dao.lock_for_update
   149→                    let layer_permit = self
   150→                        .layer_permit_service
   151→                        .send(Request {
   152→                            id: layer.id,
   153→                            duration: Duration::from_secs(2 * layer.frames.len() as u64),
   154→                        })
   155→                        .await
   156→                        .expect("Layer permit service is not available");
   157→
   158→                    if layer_permit {
   159→                        let layer_id = layer.id;
   160→                        self.process_layer(layer, cluster).await;
   161→                        debug!("{}: Processed layer", layer_disp);
   162→
   163→                        self.layer_permit_service
   164→                            .send(Release { id: layer_id })
   165→                            .await
   166→                            .expect("Layer permit service is not available");
   167→
   168→                        processed_layers.fetch_add(1, Ordering::Relaxed);
   169→                    } else {
   170→                        debug!(
   171→                            "Layer skipped. {} already being processed by another task.",
   172→                            layer
   173→                        );
   174→                    }
   175→                }
   176→
   177→                if processed_layers.load(Ordering::Relaxed) == 0 {
   178→                    WASTED_ATTEMPTS.fetch_add(1, Ordering::Relaxed);
   179→                    debug!("Job {} didn't process any layer", job_disp);
   180→                }
   181→            }
   182→            Err(err) => {
   183→                error!("Failed to query layers. {:?}", err);
   184→            }
   185→        }
   186→    }
