   188→    /// Validates whether a host is suitable for a specific layer.
   189→    ///
   190→    /// Subscriptions: Check whether this hosts' subscription can book at least one frame
   191→    ///
   192→    /// # Arguments
   193→    ///
   194→    /// * `_host` - The host to validate
   195→    /// * `_layer_id` - The layer ID to validate against
   196→    ///
   197→    /// # Returns
   198→    ///
   199→    /// * `bool` - True if the match is valid
   200→    fn validate_match(
   201→        host: &Host,
   202→        _layer_id: &Uuid,
   203→        show_id: &Uuid,
   204→        cores_requested: CoreSize,
   205→        allocation_service: &AllocationService,
   206→        os: Option<&str>,
   207→    ) -> bool {
   208→        // Check OS compatibility
   209→        if host.str_os.as_deref() != os {
   210→            return false;
   211→        }
   212→
   213→        if let Some(subscription) = allocation_service.get_subscription(&host.alloc_name, show_id) {
   214→            if !subscription.bookable(&cores_requested) {
   215→                return false;
   216→            }
   217→        } else {
   218→            return false;
   219→        };
   220→
   221→        true
   222→    }
