   408→    /// Handles various dispatch errors with appropriate logging and actions.
   409→    ///
   410→    /// Uses pre-computed layer info since the layer ownership may have been moved.
   411→    /// Different error types result in different log levels and recovery strategies.
   412→    ///
   413→    /// # Arguments
   414→    ///
   415→    /// * `error` - The dispatch error that occurred
   416→    /// * `layer_display` - Pre-computed display string for the layer
   417→    /// * `layer_job_id` - The job ID from the layer
   418→    /// * `host` - The host that the dispatch was attempted on
   419→    fn log_dispatch_error_with_info(
   420→        error: DispatchError,
   421→        layer_display: &str,
   422→        layer_job_id: &Uuid,
   423→        host: &Host,
   424→    ) {
   425→        match error {
   426→            DispatchError::HostLock(host_name) => {
   427→                info!("Failed to acquire lock for host {}", host_name)
   428→            }
   429→            DispatchError::Failure(report) => {
   430→                error!(
   431→                    "{:?}",
   432→                    report.wrap_err(format!("Failed to dispatch {} on {}.", layer_display, host))
   433→                );
   434→            }
   435→            DispatchError::AllocationOverBurst(allocation_name) => {
   436→                let msg = format!(
   437→                    "Skiping host in this selection for {}. Allocation {} is over burst.",
   438→                    layer_job_id, allocation_name
   439→                );
   440→                info!(msg);
   441→            }
   442→            DispatchError::FailedToStartOnDb(sqlx_error) => {
   443→                error!(
   444→                    "Failed to Start frame on Database when dispatching {} on {}. {:?}",
   445→                    layer_display, host, sqlx_error
   446→                );
   447→            }
   448→            DispatchError::DbFailure(error) => {
   449→                error!(
   450→                    "Failed to Start due to database error when dispatching {} on {}. {:?}",
   451→                    layer_display, host, error
   452→                );
   453→            }
   454→            DispatchError::FailureGrpcConnection(_, report) => {
   455→                error!(
   456→                    "{:?}",
   457→                    report.wrap_err(format!(
   458→                        "{} failed to create a GRPC connection to {}.",
   459→                        layer_display, host
   460→                    ))
   461→                );
   462→            }
   463→            DispatchError::GrpcFailure(status) => {
   464→                error!(
   465→                    "{} failed to create execute grpc command on {}. {:?}",
   466→                    layer_display, host, status
   467→                );
   468→            }
   469→            DispatchError::FailedToCreateProc {
   470→                error,
   471→                frame_id,
   472→                host_id,
   473→            } => {
   474→                error!(
   475→                    "Failed to create proc for frame {} on host {}. {:?}",
   476→                    frame_id, host_id, error
   477→                );
   478→            }
   479→            DispatchError::FailedToUpdateResources(report) => {
   480→                error!(
   481→                    "{:?}",
   482→                    report.wrap_err(format!(
   483→                        "Failed to update resources for dispatching {} on {}.",
   484→                        layer_display, host
   485→                    ))
   486→                );
   487→            }
   488→        }
   489→    }

