    29→/// Runs the scheduler feed loop, processing jobs for each cluster.
    30→///
    31→/// Iterates through the cluster feed, fetching and processing jobs for each cluster.
    32→/// Jobs are processed concurrently within configurable buffer sizes. The loop can
    33→/// optionally terminate after a configured number of empty cycles.
    34→///
    35→/// # Arguments
    36→///
    37→/// * `cluster_feed` - Iterator over clusters to process
    38→///
    39→/// # Returns
    40→///
    41→/// * `Ok(())` - Scheduler completed successfully
    42→/// * `Err(miette::Error)` - Fatal error occurred during processing
    43→pub async fn run(cluster_feed: Arc<ClusterFeed>) -> miette::Result<()> {
    44→    let job_fetcher = Arc::new(JobDao::new().await?);
    45→    let matcher = Arc::new(MatchingService::new().await?);
    46→    let cycles_without_jobs = Arc::new(AtomicUsize::new(0));
    47→    info!("Starting scheduler feed");
    48→
    49→    let (tx, cluster_receiver) = mpsc::channel(16);
    50→    let feed_sender = cluster_feed.stream(tx).await;
    51→
    52→    ReceiverStream::new(cluster_receiver)
    53→        .for_each_concurrent(CONFIG.queue.stream.cluster_buffer_size, |cluster| {
    54→            let job_fetcher = job_fetcher.clone();
    55→            let matcher = matcher.clone();
    56→            let cycles_without_jobs = cycles_without_jobs.clone();
    57→            let feed_sender = feed_sender.clone();
    58→
    59→            async move {
    60→                let jobs = job_fetcher
    61→                    .query_pending_jobs_by_show_facility_and_tags(
    62→                        cluster.show_id,
    63→                        cluster.facility_id,
    64→                        cluster.tags.iter().map(|tag| tag.name.clone()),
    65→                    )
    66→                    .await;
    67→
    68→                match jobs {
    69→                    Ok(jobs) => {
    70→                        // Track number of jobs queried
    71→                        metrics::increment_jobs_queried(jobs.len());
    72→
    73→                        let processed_jobs = AtomicUsize::new(0);
    74→                        stream::iter(jobs)
    75→                            .for_each_concurrent(
    76→                                CONFIG.queue.stream.job_buffer_size,
    77→                                |job_model| async {
    78→                                    processed_jobs.fetch_add(1, Ordering::Relaxed);
    79→                                    metrics::increment_jobs_processed(&job_model.show_name);
    80→                                    let job = DispatchJob::new(job_model, cluster.clone());
    81→                                    debug!("Found job: {}", job);
    82→                                    matcher.process(job).await;
    83→                                },
    84→                            )
    85→                            .await;
    86→                        // If no jobs got processed, sleep to prevent hammering the database with
    87→                        // queries with no outcome
    88→                        if processed_jobs.load(Ordering::Relaxed) == 0 {
    89→                            let _ = feed_sender
    90→                                .send(FeedMessage::Sleep(cluster, Duration::from_secs(3)))
    91→                                .await;
    92→                        }
    93→
    94→                        // If empty_jobs_cycles_before_quiting is set, quit if nothing got processed
    95→                        if let Some(limit) = CONFIG.queue.empty_job_cycles_before_quiting {
    96→                            // Count cycles that couldn't find any job
    97→                            if processed_jobs.load(Ordering::Relaxed) == 0 {
    98→                                cycles_without_jobs.fetch_add(1, Ordering::Relaxed);
    99→                            } else {
   100→                                cycles_without_jobs.store(0, Ordering::Relaxed);
   101→                            }
   102→
   103→                            // Cancel stream processing after empty cycles
   104→                            if cycles_without_jobs.load(Ordering::Relaxed) >= limit {
   105→                                let _ = feed_sender.send(FeedMessage::Stop()).await;
   106→                            }
   107→                        }
   108→                    }
   109→                    Err(err) => {
   110→                        let _ = feed_sender.send(FeedMessage::Stop()).await;
   111→                        error!("Failed to fetch job: {}", err);
   112→                    }
   113→                }
   114→            }
   115→        })
   116→        .await;
   117→
   118→    Ok(())
   119→}
